parameters.jsCode:
return [{
  json: {
    source: 'employee_chat',
    employee: {
      name: 'Sarah Chen',
      id: 'EMP_4821',
      department: 'Sales',
      level: 'manager'
    },
    request: 'Schedule onboarding for new hire Monday, book conference room B tomorrow 2pm, submit expense report for SF trip',
    detectedIntents: ['hr_onboarding', 'room_booking', 'expense_submission']
  }
}];

const req = $input.first().json;

const skills = {
  hr_onboarding: { name: 'HR Onboarding Agent', autonomy: 'high' },
  room_booking: { name: 'Workspace Agent', autonomy: 'high' },
  expense_submission: { name: 'Finance Agent', autonomy: 'medium' }
};

const activatedSkills = req.detectedIntents.map(intent => ({
  intent, skill: skills[intent]
}));

return [{
  json: {
    ...req,
    activatedSkills,
    skillsCount: activatedSkills.length
  }
}];

return [{
  json: {
    skill: 'hr_onboarding',
    actionsCompleted: 4,
    newHire: 'Alex Johnson',
    startDate: '2026-03-03'
  }
}];

return [{
  json: {
    skill: 'room_booking',
    actionsCompleted: 4,
    room: 'Conference Room B',
    time: '2026-02-28 14:00'
  }
}];

return [{
  json: {
    skill: 'expense_submission',
    actionsCompleted: 3,
    total: 855,
    status: 'pending_approval',
    reportId: 'EXP-2026-8847'
  }
}];

const results = $input.all().map(item => item.json);
const totalActions = results.reduce((sum, r) => sum + r.actionsCompleted, 0);

return [{
  json: {
    employee: 'Sarah Chen',
    skillsActivated: results.length,
    totalActionsCompleted: totalActions,
    details: results.map(r => r.skill + ': ' + r.actionsCompleted + ' actions')
  }
}];

